class BankingSecurityCallbackHandler implements CallbackHandler {
    @Override
    public void handle(Callback[] callbacks) throws UnsupportedCallbackException {
        for (Callback callback : callbacks) {
            if (callback instanceof WSPasswordCallback) {
                WSPasswordCallback pc = (WSPasswordCallback) callback;
                if ("banking-signing-key".equals(pc.getIdentifier())) {
                    pc.setPassword("changeit");
                } else if ("banking-trust-key".equals(pc.getIdentifier())) {
                    pc.setPassword("changeit");
                }
            }
        }
    }
}

class SignedElementsCaptureInterceptor extends AbstractPhaseInterceptor<SoapMessage> {

    public SignedElementsCaptureInterceptor() {
        super(Phase.PRE_INVOKE);
    }

    @Override
    public void handleMessage(SoapMessage message) throws Fault {
        try {
            Document doc = message.getContent(Document.class);
            if (doc == null && message.getContent(InputStream.class) != null) {
                byte[] bytes = readAll(message.getContent(InputStream.class));
                message.setContent(InputStream.class, new ByteArrayInputStream(bytes));
                DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
                dbf.setNamespaceAware(true);
                dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
                dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
                DocumentBuilder db = dbf.newDocumentBuilder();
                doc = db.parse(new ByteArrayInputStream(bytes));
            }
            if (doc != null) {
                SignatureVerificationResult result = XmlSignatureVerifier.verify(doc);
                message.put("banking.signature.valid", result.isValid());
                message.put("banking.signature.signer", result.getSignerSubject());
                message.put("banking.signature.signedElements", result.getSignedElementQNames());
            }
        } catch (Exception e) {
            throw new Fault(e);
        }
    }

    private byte[] readAll(InputStream is) throws Exception {
        ByteArrayOutputStream bos = new ByteArrayOutputStream();
        byte[] buf = new byte[4096];
        int r;
        while ((r = is.read(buf)) != -1) {
            bos.write(buf, 0, r);
        }
        return bos.toByteArray();
    }
}

